131	/// A helper type that allows matching combinations of `WhatAmI` values in scouting.
132	///
133	/// The [`scout`](crate::scouting::scout) function accepts a `WhatAmIMatcher` to filter the nodes
134	/// of the specified types. The `WhatAmIMatcher` can be constructed from [`WhatAmI`] values
135	/// with the `|` operator
136	#[repr(transparent)]
137	#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
138	pub struct WhatAmIMatcher(NonZeroU8);
139	
140	impl WhatAmIMatcher {
141	    // We use the 7th bit for detecting whether the WhatAmIMatcher is non-zero
142	    const U8_0: u8 = 1 << 7;
143	    const U8_R: u8 = Self::U8_0 | WhatAmI::U8_R;
144	    const U8_P: u8 = Self::U8_0 | WhatAmI::U8_P;
145	    const U8_C: u8 = Self::U8_0 | WhatAmI::U8_C;
146	    const U8_R_P: u8 = Self::U8_0 | WhatAmI::U8_R | WhatAmI::U8_P;
147	    const U8_P_C: u8 = Self::U8_0 | WhatAmI::U8_P | WhatAmI::U8_C;
148	    const U8_R_C: u8 = Self::U8_0 | WhatAmI::U8_R | WhatAmI::U8_C;
149	    const U8_R_P_C: u8 = Self::U8_0 | WhatAmI::U8_R | WhatAmI::U8_P | WhatAmI::U8_C;
150	
151	    /// Creates an empty `WhatAmIMatcher`, which matches no `WhatAmI` values.
152	    pub const fn empty() -> Self {
153	        Self(unsafe { NonZeroU8::new_unchecked(Self::U8_0) })
154	    }
155	
156	    /// Creates a `WhatAmIMatcher` matching all [`WhatAmI::Router`] values.
157	    pub const fn router(self) -> Self {
158	        Self(unsafe { NonZeroU8::new_unchecked(self.0.get() | Self::U8_R) })
159	    }
160	
161	    /// Creates a `WhatAmIMatcher` matching all [`WhatAmI::Peer`] values.
162	    pub const fn peer(self) -> Self {
163	        Self(unsafe { NonZeroU8::new_unchecked(self.0.get() | Self::U8_P) })
164	    }
165	
166	    /// Creates a `WhatAmIMatcher` matching all [`WhatAmI::Client`] values.
167	    pub const fn client(self) -> Self {
168	        Self(unsafe { NonZeroU8::new_unchecked(self.0.get() | Self::U8_C) })
169	    }
170	
171	    /// Returns whether the `WhatAmIMatcher` is empty.
172	    pub const fn is_empty(&self) -> bool {
173	        self.0.get() == Self::U8_0
174	    }
175	
176	    /// Returns whether the `WhatAmIMatcher` matches the given `WhatAmI` value.
177	    pub const fn matches(&self, w: WhatAmI) -> bool {
178	        (self.0.get() & w as u8) != 0
179	    }
180	
181	    /// Returns a string representation of the `WhatAmIMatcher` as a combination of
182	    /// `WhatAmI` string representations separated by `|`.
183	    pub const fn to_str(self) -> &'static str {
